const data = $input.first().json;

const learnNextHK = Array.isArray(data.learn_next) && data.learn_next.length > 0
  ? data.learn_next[0]
  : null;

const learnedHK = Array.isArray(data.learned) && data.learned.length > 0
  ? data.learned.join(", ")
  : null;

const learnNextSubjects = Array.isArray(data.learn_next_subjects)
  ? data.learn_next_subjects.filter(r => r["Tên học phần"])
  : [];

const failedSubjects = Array.isArray(data.failedSubjects)
  ? data.failedSubjects
  : [];

const affectedSubjects = Array.isArray(data.affectedSubjects)
  ? data.affectedSubjects
  : [];

const failValue = data.fail?.value === true;

const rawQuestion = data.rawQuestion || null;

// =========================
// CASE 0: KHÔNG CÓ MÔN NÀO
// =========================
if (!learnNextHK || learnNextSubjects.length === 0) {
  return [{
    json: {
      model: $env.AI_MODEL,
      temperature: 0,
      messages: [
        {
          role: "system",
          content: `
Bạn là trợ lý tư vấn học tập.
Chỉ sử dụng dữ liệu được cung cấp.
Không suy luận.
          `.trim()
        },
        {
          role: "assistant",
          content: "Không tìm được môn học phù hợp để tư vấn cho sinh viên."
        }
      ]
    }
  }];
}

// =========================
// BUILD: MÔN ĐÃ HỌC
// =========================
const learnedText = learnedHK
  ? `Sinh viên đã hoàn thành học kỳ: ${learnedHK}.`
  : "Không có thông tin học kỳ đã học.";

// =========================
// BUILD: MÔN SẼ HỌC
// =========================
let learnNextList = "";

learnNextSubjects.forEach(r => {
  let line = `- ${r["Tên học phần"]} (${r["Số tín chỉ"]} tín chỉ)`;

  if (r["Bắt buộc/Tự chọn"] === "BB") {
    line += " – Bắt buộc";
  } else {
    line += ` – Tự chọn – Nhóm: ${r.group || "Không rõ nhóm"}`;
  }

  learnNextList += line + "\n";
});

// =========================
// CASE 1: FAIL MODE
// =========================
if (failValue) {
  let failedList = "";
  let affectedList = "";

  failedSubjects.forEach(r => {
    failedList += `- ${r["Tên học phần"]} (${r["Số tín chỉ"]} tín chỉ)\n`;
  });

  affectedSubjects.forEach(r => {
    if (r["Bắt buộc/Tự chọn"] === "BB") {
      affectedList += `- ${r["Tên học phần"]} (HK ${r["Phân bổ học kỳ"]}) – môn bắt buộc, nên học lại sớm nhất có thể\n`;
    } else {
      affectedList += `- ${r["Tên học phần"]} (HK ${r["Phân bổ học kỳ"]}) – môn tự chọn, cân nhắc học lại hoặc chọn môn khác\n`;
    }
  });

  return [{
    json: {
      model: $env.AI_MODEL,
      temperature: 0.3,
      messages: [
        {
          role: "system",
          content: `
Bạn là hệ thống diễn giải dữ liệu học tập.

VAI TRÒ:
- Chuyển dữ liệu học vụ do hệ thống cung cấp thành đoạn văn dễ đọc, tự nhiên
- Có thể đưa ra gợi ý học tập dựa vào thông tin đã cho chứ không được chế thêm thông tin

