const items = $input.all();

/* ======================================================
 * UTILITY FUNCTIONS
 * ====================================================== */

function normalizeText(str = '') {
  return String(str)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function parseHK(val) {
  if (!val) return null;
  const m = /hk\s*(\d+)/i.exec(String(val));
  return m ? Number(m[1]) : null;
}

function isValidSubjectRow(r) {
  if (!r) return false;
  const name = String(r['Tên học phần'] || '').trim();
  const code = String(r['Mã học phần'] || '').trim();
  const tc = Number(r['Số tín chỉ']);
  if (!name || !code || !tc || isNaN(tc)) return false;
  if (/\s/.test(code)) return false;
  return true;
}

/* ======================================================
 * EXTRACT DATA FROM FilterHelp OUTPUT
 * ====================================================== */

let inputData = null;

for (const item of items) {
  if (item.json?.learn_next_subjects && item.json?.failedSubjects && item.json?.affectedSubjects) {
    inputData = item.json;
    break;
  }
}

if (!inputData) {
  return [{
    json: {
      total: 0,
      learn_next_subjects: []
    }
  }];
}

/* ======================================================
 * GET SUBJECT NAMES FROM FILTER 1 OUTPUT
 * ====================================================== */

const filter1Subjects = [
  ...(inputData.learn_next_subjects || []),
  ...(inputData.failedSubjects || []),
  ...(inputData.affectedSubjects || [])
];

// CREATE SET OF VALID SUBJECT NAMES (normalized)
const validSubjectNames = new Set();

filter1Subjects.forEach(s => {
  const name = normalizeText(s['_tenHocPhan_norm'] || s['Tên học phần'] || '');
  if (name) validSubjectNames.add(name);
});

/* ======================================================
 * GET NEW DATA FROM CACHE
 * ====================================================== */

let newCacheData = [];

for (const item of items) {
  if (typeof item.json?.data === 'string' && item.json?.cache_key === 'sheet_cache') {
    try {
      const parsed = JSON.parse(item.json.data);
      if (Array.isArray(parsed)) {
        newCacheData = parsed;
        break;
      }
    } catch {}
  }
}

/* ======================================================
 * FILTER NEW DATA BY EXACT SUBJECT NAME MATCH
 * ====================================================== */

const filteredNewData = newCacheData.filter(row => {
  const tenHP = normalizeText(row['_tenHocPhan_norm'] || row['Tên HP'] || '');
  return validSubjectNames.has(tenHP);
});

/* ======================================================
 * GROUP AND FORMAT next_subject DATA
 * ====================================================== */

// Extract class code from Mã LHP (e.g., "252_71ITSE30803_01" -> "01")
function extractClassCode(maLHP) {
  if (!maLHP) return '';
  const parts = String(maLHP).split('_');
  return parts[parts.length - 1] || '';
}

// Group by subject (Mã MH)
const subjectGroups = new Map();

filteredNewData.forEach(row => {
  const maMH = row['Mã MH'];
  if (!subjectGroups.has(maMH)) {
    subjectGroups.set(maMH, []);
  }
  subjectGroups.get(maMH).push(row);
});

// Format each subject group
const formattedNextSubject = [];

subjectGroups.forEach((rows, maMH) => {
  // Separate theory and practice classes
  const theoryClasses = rows.filter(r => normalizeText(r['Loại HP']) === 'ly thuyet');
  const practiceClasses = rows.filter(r => normalizeText(r['Loại HP']) === 'thuc hanh');

  // Process each theory class
  theoryClasses.forEach(theory => {
    const theoryCode = extractClassCode(theory['Mã LHP']);

    const subjectData = {
      'Tên HP': theory['Tên HP'],
      'Mã LHP': theoryCode,
      'Loại HP': theory['Loại HP'],
      'Thứ': theory['Thứ'],
      'Tiết Học': theory['Tiết Học'],
      'Phòng': theory['Phòng'],
      'practice': []
    };

    // Find matching practice classes (first 2 digits match theory code)
    practiceClasses.forEach(practice => {
      const practiceCode = extractClassCode(practice['Mã LHP']);

      // Check if practice belongs to this theory (e.g., 0101 belongs to 01)
      if (practiceCode.startsWith(theoryCode)) {
        subjectData.practice.push({
          'Loại HP': practice['Loại HP'],
          'Mã LHP': practiceCode,
          'Thứ': practice['Thứ'],
          'Tiết Học': practice['Tiết Học'],
          'Phòng': practice['Phòng']
        });
      }
    });

    formattedNextSubject.push(subjectData);
  });

  // Handle standalone practice classes (no matching theory)
  practiceClasses.forEach(practice => {
    const practiceCode = extractClassCode(practice['Mã LHP']);
    const hasTheory = theoryClasses.some(t => practiceCode.startsWith(extractClassCode(t['Mã LHP'])));

    if (!hasTheory) {
      formattedNextSubject.push({
        'Tên HP': practice['Tên HP'],
        'Mã LHP': practiceCode,
        'Loại HP': practice['Loại HP'],
        'Thứ': practice['Thứ'],
        'Tiết Học': practice['Tiết Học'],
        'Phòng': practice['Phòng'],
        'practice': []
      });
    }
  });
});

/* ======================================================
 * REMOVE DUPLICATES FROM FILTER 1 DATA
 * ====================================================== */

const uniqueMap = new Map();
const priority = { 'fail': 5, 'fail2': 4, 'fail1': 3, 'learn_next': 2, 'next': 1 };

filter1Subjects.forEach(subject => {
  if (!isValidSubjectRow(subject)) return;

  const code = subject['Mã học phần'];
  const existing = uniqueMap.get(code);

  if (!existing) {
    uniqueMap.set(code, subject);
  } else {
    const existingStatus = existing.fail || existing.type || existing.learn_status;
    const currentStatus = subject.fail || subject.type || subject.learn_status;

    const existingPriority = priority[existingStatus] || 0;
    const currentPriority = priority[currentStatus] || 0;

    if (currentPriority > existingPriority) {
      uniqueMap.set(code, subject);
    }
  }
});

const cleanedFilter1Data = Array.from(uniqueMap.values());

/* ======================================================
 * OUTPUT - 2 SEPARATE JSON OBJECTS
 * ====================================================== */

return [
  // JSON 1: CTDT Data
  {
    json: {
      typeTT: 'CTDT',
      rawQuestion: inputData.rawQuestion,
      intent: inputData.intent,
      course: inputData.course,
      industry: inputData.industry,
      semester: inputData.semester,
      learned: inputData.learned,
      learn_next: inputData.learn_next,
      currentHK: inputData.currentHK,
      fail: inputData.fail,
      total: cleanedFilter1Data.length,
      learn_next_subjects: cleanedFilter1Data
    }
  },
  // JSON 2: Class Schedule Data
  {
    json: {
      typeTT: 'MH',
      total_next_subject: formattedNextSubject.length,
      next_subject: formattedNextSubject
    }
  }
];

