const items = $input.all();
const major = $('configAI').first().json.major;

// --------------------
// UTIL
// --------------------
function normalizeText(str = '') {
  return str
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function isValidSubject(item) {
  const name = String(item["Tên học phần"] || "").trim();
  const code = String(item["Mã học phần"] || "").trim();
  const credit = String(item["Số tín chỉ"] || "").trim();

  if (!name) return false;

  // loại dòng group
  if (!code) return false;

  // phải có tín chỉ
  if (!credit) return false;

  return true;
}

function isNearExactMatch(keywordNorm, subjectNorm) {
  const kwTokens = keywordNorm.split(' ');
  const nameTokens = subjectNorm.split(' ');
  return kwTokens.every(t => nameTokens.includes(t));
}

function getMatchLevel(keywordNorm, nameNorm, nameBase) {

  // LEVEL 1
  if (nameNorm === keywordNorm) return 1;

  // LEVEL 2
  if (isNearExactMatch(keywordNorm, nameNorm)) return 2;

  // LEVEL 3
  const kwTokens = keywordNorm.split(" ");
  const nameTokens = nameBase.split(" ");

  let count = 0;

  for (const t of kwTokens) {
    if (nameTokens.includes(t)) count++;
  }

  const ratio = count / kwTokens.length;

  // match mạnh
  if (ratio >= 0.7) return 3;

  // fallback: keyword dài ≥ 4 ký tự
  if (kwTokens.length === 1 && keywordNorm.length >= 4) {
    if (nameBase.includes(keywordNorm)) return 3;
  }

  return 0;
}

// --------------------
// 1. TÁCH DATA + QUERY
// --------------------
let dataset = [];
let query = null;

for (const item of items) {

  const json = item.json || {};

  if (typeof json.data === "string") {
    try {
      const parsed = JSON.parse(json.data);
      if (Array.isArray(parsed)) dataset.push(...parsed);
    } catch {}
  }

  if (Array.isArray(json.subjects) || json.query_target) {
    query = json;
  }

}

// --------------------
// GUARD
// --------------------
if (!query) {
  return [{
    json: {
      type: "CTDT",
      reason: "NO_QUERY",
      total: 0,
      data: []
    }
  }];
}

// --------------------
// QUERY FIELD
// --------------------
const totalCreditQuery = query.total_credit === true;
const subjects = query.subjects || [];
const semester = query.semester || "";
const credit = query.credit;
const bb_tc = query.bb_tc;
const prerequisiteSubjects = query.prerequisite_subjects || [];
const target = query.query_target;

const semesterNorm = semester ? semester.toUpperCase() : "";
const subjectNorm = subjects.map(s => normalizeText(s));
const prerequisiteNorm = prerequisiteSubjects.map(s => normalizeText(s));

// --------------------
// SINGLE LOOP FILTER
// --------------------
let bestLevel = 999;
let tempMatches = [];

for (const item of dataset) {
  if (!isValidSubject(item)) continue;
  if (semesterNorm) {
    if (String(item["Phân bổ học kỳ"]).toUpperCase() !== semesterNorm) continue;
  }

  if (credit != null) {
    if (Number(item["Số tín chỉ"]) !== Number(credit)) continue;
  }

  const type = String(item["Bắt buộc/Tự chọn"] || "").toUpperCase();

  if (bb_tc === "tc") {
    if (!type.includes("TC")) continue;
  }

  if (bb_tc === "bb") {
    if (!type.includes("BB")) continue;
  }

  if (target === "subject_list" && major) {
    const groupNorm = normalizeText(item["group"] || "");
    if (groupNorm.includes("chuyen nganh")) {
      if (!groupNorm.includes(major)) continue;
    }
  }

  let level = 0;

  if (subjectNorm.length > 0) {

    const name = item["Tên học phần"];
    const nameNorm = normalizeText(name);
    const nameBase = normalizeText(item["_tenHocPhan_norm"] || name);

    for (const kw of subjectNorm) {

      const l = getMatchLevel(kw, nameNorm, nameBase);

      if (l > 0) {
        level = l;
        break;
      }

    }

    if (level === 0) continue;
  }

  if (prerequisiteNorm.length > 0) {

    const dk = normalizeText(item["ĐK tiên quyết"] || "");

    let ok = false;

    for (const sub of prerequisiteNorm) {
      if (dk.includes(sub)) {
        ok = true;
        break;
      }
    }

    if (!ok) continue;
  }

  if (level < bestLevel) {
    bestLevel = level;
    tempMatches = [item];
  } 
  else if (level === bestLevel) {
    tempMatches.push(item);
  }

}

// --------------------
// TOTAL CREDIT
// --------------------

let totalCredit = null;

if (totalCreditQuery) {

  if (semesterNorm) {

  let seen = new Set();

  for (const item of dataset) {

    if (!isValidSubject(item)) continue;

    const hk = String(item["Phân bổ học kỳ"] || "").toUpperCase();

    if (hk !== semesterNorm) continue;

    const tc = Number(item["Số TC/ HK"] || 0);

    if (tc > 0) seen.add(tc);

  }

  totalCredit = [...seen].reduce((a,b)=>a+b,0);

} else {

    // tổng tín chỉ toàn khóa
    const semesters = new Map();

    for (const item of dataset) {

      if (!isValidSubject(item)) continue;

      const hk = String(item["Phân bổ học kỳ"] || "").toUpperCase();

      if (!hk) continue;

      const tc = Number(item["Số TC/ HK"] || 0);

      if (!semesters.has(hk)) {
        semesters.set(hk, tc);
      }

    }

    totalCredit = [...semesters.values()].reduce((a,b)=>a+b,0);

  }

}

// --------------------
// RESULT
// --------------------
const result = tempMatches.map(item => ({
  "Mã học phần": item["Mã học phần"],
  "Phân bổ học kỳ": item["Phân bổ học kỳ"],
  "Tên học phần": item["Tên học phần"],
  "Số tín chỉ": item["Số tín chỉ"],
  "Bắt buộc/Tự chọn": item["Bắt buộc/Tự chọn"],
  "ĐK tiên quyết": item["ĐK tiên quyết"],
  "ĐK học trước": item["ĐK học trước"],
  "group": item["group"]
}));

// --------------------
// OUTPUT
// --------------------
return [{
  json: {
    type: "CTDT",
    query_target: target,
    subjects,
    semester,
    credit,
    bb_tc,
    prerequisite_subjects: prerequisiteSubjects,
    total_credit: totalCreditQuery,
    total_credit_value: totalCredit,
    total: result.length,
    data: result
  }
}];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

