function normalize(text) {
  return String(text || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

// ======================
// NORMALIZE THỨ
// ======================
function normalizeThu(text) {

  const t = normalize(text);

  if (t.includes("thu 2") || t.includes("thu hai")) return "thu 2";
  if (t.includes("thu 3") || t.includes("thu ba")) return "thu 3";
  if (t.includes("thu 4") || t.includes("thu bon")) return "thu 4";
  if (t.includes("thu 5") || t.includes("thu nam")) return "thu 5";
  if (t.includes("thu 6") || t.includes("thu sau")) return "thu 6";
  if (t.includes("thu 7") || t.includes("thu bay")) return "thu 7";
  if (t.includes("chu nhat")) return "cn";

  return "";
}

// ======================
// NORMALIZE PERIOD
// ======================
function normalizePeriod(text) {

  const t = String(text || "").trim();

  const match = t.match(/^(\d{1,2})\s*-\s*(\d{1,2})$/);

  if (!match) return "";

  return `${match[1]} - ${match[2]}`;
}

function matchSubjectName(rowName, subjectName) {

  const rowTokens = normalize(rowName).split(/\s+/);
  const subjectTokens = normalize(subjectName).split(/\s+/);

  return subjectTokens.every(token => rowTokens.includes(token));
}

// ======================
// MATCH SUBJECT ROW
// ======================
function matchSubjectRow(row, subject) {

  const rowName = row["_tenHocPhan_norm"] || row["Tên HP"];

  if (!matchSubjectName(rowName, subject.name)) return false;

  // day
  if (subject.day) {

    const rowThu = normalizeThu(row["Thứ"]);
    const subjectThu = normalizeThu(subject.day);

    if (rowThu !== subjectThu) return false;
  }

  // period
  if (subject.period) {

    const rowPeriod = normalizePeriod(row["Tiết Học"]);
    const subjectPeriod = normalizePeriod(subject.period);

    if (rowPeriod !== subjectPeriod) return false;
  }

  // room
  if (subject.room) {

    const roomNorm = normalize(row["Phòng"]);
    const subjectRoom = normalize(subject.room);

    if (!roomNorm.includes(subjectRoom)) return false;
  }

  return true;
}

// ======================
// FILTER
// ======================
let matchedRows = [];

for (const subject of subjects) {

  const filtered = rows.filter(row => {

    if (!matchSubjectRow(row, subject)) return false;

    if (classCode) {
      const classNorm = normalize(classCode);
      const rowClass = row["Mã LHP"] || "";
      const classPart = rowClass.split("_").pop();
      if (classNorm && classPart !== classNorm) return false;
    }

    return true;

  });

  matchedRows.push(...filtered);
}

