function unwrapValue(v, maxDepth = 5) {
  let cur = v;
  let depth = 0;

  while (
    cur &&
    typeof cur === 'object' &&
    !Array.isArray(cur) &&
    depth < maxDepth
  ) {
    const keys = Object.keys(cur);
    if (keys.length !== 1) break;
    cur = cur[keys[0]];
    depth++;
  }

  return cur;
}

